class Solution {
public:
    ListNode* mergeKLists(vector<ListNode*>& lists) {
        int n = lists.size();
        ListNode head(0); // Initialize the head node
        ListNode* curr = &head;
        for (int i = 0; i < n; i++) {
            ListNode* curr_list = lists[i];
            while (curr_list) {
                curr->next = curr_list;
                curr = curr->next;
                curr_list = curr_list->next;
            }
        }
        return head.next;
    }
};
```

